import React, { useState } from "react";
import TreeView from "./TreeView";
import CategoryView from "./CategoryView";

const EditorialFlow: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'tree' | 'category'>('tree');

  return (
    <div className="bg-white dark:bg-gray-800 rounded-lg shadow flex-1 overflow-hidden border border-gray-200 dark:border-gray-700">
      {/* Onglets */}
      <div className="bg-gray-50 dark:bg-gray-700/50 px-6 py-4 border-b border-gray-200 dark:border-gray-700">
        <div className="flex gap-4">
          <button
            onClick={() => setActiveTab('tree')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
              activeTab === 'tree'
                ? 'bg-purple-600 text-white shadow-lg'
                : 'bg-gray-200 dark:bg-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-500'
            }`}
          >
            <i className="fas fa-sitemap"></i>
            Arborescence
          </button>
          <button
            onClick={() => setActiveTab('category')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
              activeTab === 'category'
                ? 'bg-purple-600 text-white shadow-lg'
                : 'bg-gray-200 dark:bg-gray-600 text-gray-700 dark:text-gray-300 hover:bg-gray-300 dark:hover:bg-gray-500'
            }`}
          >
            <i className="fas fa-folder"></i>
            Par Rubriques
          </button>
        </div>
      </div>

      {/* Contenu des onglets */}
      <div className="p-6 overflow-y-auto" style={{ maxHeight: 'calc(100vh - 280px)' }}>
        {activeTab === 'tree' ? <TreeView /> : <CategoryView />}
      </div>
    </div>
  );
};

export default EditorialFlow;
